import React, { type FC, useState, useCallback } from "react";
import type { IEditableProps } from "@lmb-it/kitsconcerto-types";

import { Text, Flex, Button, KitsInputText, KitsInputTextarea } from "../../_compat";


const Editable: FC<IEditableProps> = ({
                                          defaultValue = "",
                                          value,
                                          onChange,
                                          onSubmit,
                                          activationMode = "click",
                                          disabled = false,
                                          type = "input",
                                          previewProps,
                                          inputProps,
                                          textareaProps,
                                          controls,
                                      }) => {
    const [isEditing, setIsEditing] = useState(false);
    const [internalValue, setInternalValue] = useState(defaultValue);

    const val = value ?? internalValue;

    const startEditing = () => {
        if (!disabled) setIsEditing(true);
    };

    const stopEditing = useCallback(() => {
        setIsEditing(false);
        onSubmit?.(val);
        onChange?.(val);
    }, [val, onSubmit, onChange]);

    const cancelEditing = useCallback(() => {
        setIsEditing(false);
        setInternalValue(defaultValue);
    }, [defaultValue]);

    const handleInputChange = (e: { target: { value: any; }; }) => {
        setInternalValue(e.target.value);
        onChange?.(e.target.value);
    };

    return (
        <Flex flexDirection="column" justifyContent={'flex-start'} gap={10} position={'relative'}>
            {!isEditing && (
                <Text
                    onPress={activationMode === "click" ? startEditing : undefined}
                    onLongPress={activationMode === "dblclick" ? startEditing : undefined}
                    disabled={disabled}
                    py={10}
                    px={12}
                    minH={'3rem'}
                    lineHeight={'1.5rem'}
                    {...previewProps}
                >
                    {val}
                </Text>
            )}

            {isEditing && (
                <>
                    {type === "input" ? (
                        <KitsInputText
                            autoFocus
                            attached
                            value={val}
                            onChange={handleInputChange}
                            onSubmitEditing={stopEditing}
                            onKeyDown={(e: any) => {
                                if (e && 'code' in e && e.code == "Escape") {
                                    cancelEditing();
                                }
                            }}
                            {...inputProps}
                        />
                    ) : (
                        <KitsInputTextarea
                            autoFocus
                            value={val}
                            onChange={handleInputChange}
                            onSubmitEditing={stopEditing}
                            onKeyDown={(e: any) => {
                                if (e && 'code' in e && e.code == "Escape") {
                                    cancelEditing();
                                }
                            }}
                            {...textareaProps}
                        />
                    )}

                    {controls ? (
                        controls({
                            submit: stopEditing,
                            cancel: cancelEditing,
                        })
                    ) : (
                        <Flex flexDirection="row" gap={8} justifyContent="flex-end">
                            <Button
                                onPress={cancelEditing}
                                severity="danger"
                                icon="pi pi-times"
                                size="sm"
                            />
                            <Button
                                onPress={stopEditing}
                                icon="pi pi-check"
                                size="sm"
                            />
                        </Flex>
                    )}
                </>
            )}
        </Flex>
    );
};

export default Editable;
